/**
 * Generated by scripts/_research/gen-axefx2-type-applicability.ts
 * DO NOT HAND-EDIT.
 *
 * Per-(block, name) applicability records: which Axe-Fx II amp /
 * drive / delay / reverb / etc. types expose this knob in AxeEdit.
 * Decoded from AxeEdit II `__block_layout.xml` `<Page>` and
 * `<EditorControl>` per-type filter attributes (same JUCE schema
 * as AM4-Edit; see fractal-midi/src/am4/typeApplicability.ts for
 * the AM4 sibling).
 *
 * Keys match `KNOWN_PARAMS` (e.g. `amp.bright_cap`). For params
 * not in this map: assume always-on (the common case for universal
 * block params like `BLOCK_BYPASSMODE` / `BLOCK_MIX` / out-of-band
 * channel/level registers, plus any param whose XML row carries no
 * page-level or control-level gate).
 *
 * `always: true` means the parameter has at least one ungated UI
 * exposure. `gates` lists every type-enum gate the XML defines for
 * this parameter — useful as informational context (e.g. "this
 * knob is on a special Plexi page in addition to the universal
 * one"). When `always: false`, only types listed in `gates` expose
 * the knob in AxeEdit's UI.
 */

export interface ApplicabilityGate {
  /** AxeEdit symbolic enum that gates this parameter — e.g. `DISTORT_TYPE`, `DELAY_TYPE`. */
  readonly typeEnum: string;
  /** Wire indices into the gate enum at which this parameter is exposed. */
  readonly values: readonly number[];
  /** Whether the gate is on the entire `<Page>` or an individual `<EditorControl>`. */
  readonly source: 'page' | 'control';
}

export interface Applicability {
  /** True if the parameter has at least one ungated UI exposure. */
  readonly always: boolean;
  /** Type-enum gates the parameter has. May be present alongside `always: true` (special-cased pages). */
  readonly gates: readonly ApplicabilityGate[];
}

